export function getSignLabel(signId: string, language: string): string {
  if (language === 'en') return SIGN_LABELS_EN[signId] ?? signId;
  if (language === 'tr') return SIGN_LABELS_TR[signId] ?? signId;
  return SIGN_LABELS_FR[signId] ?? signId;
}
